package com.example

import com.example.controller.EventController
import com.example.db.DatabaseFactory
import com.example.repository.EventRepository
import com.example.repository.InMemoryEventRepository
import com.example.repository.PostgresEventRepository
import com.example.service.EventService
import io.ktor.serialization.kotlinx.json.json
import io.ktor.server.application.Application
import io.ktor.server.application.install
import io.ktor.server.plugins.contentnegotiation.ContentNegotiation
import io.ktor.server.plugins.statuspages.StatusPages
import io.ktor.server.response.respond
import io.ktor.server.routing.get
import io.ktor.server.routing.routing

fun Application.module() {
    install(ContentNegotiation) {
        json()
    }

    install(StatusPages) {
        exception<IllegalArgumentException> { call, cause ->
            call.respond(mapOf("error" to cause.message.orEmpty()))
        }
    }

    val repository: EventRepository = when ((System.getenv("EVENTS_STORAGE") ?: "memory").lowercase()) {
        "postgres", "postgresql" -> {
            val dataSource = DatabaseFactory.createPostgresDataSource()
            DatabaseFactory.initializeSchema(dataSource)
            PostgresEventRepository(dataSource)
        }
        else -> InMemoryEventRepository()
    }

    val service = EventService(repository)
    val controller = EventController(service)

    routing {
        get("/health") {
            call.respond(mapOf("status" to "ok"))
        }
        controller.register(this)
    }
}

package com.example

import com.example.controller.EventController
import com.example.db.DatabaseFactory
import com.example.db.dao.JdbcEventDao
import com.example.repository.EventRepository
import com.example.repository.InMemoryEventRepository
import com.example.repository.PostgresEventRepository
import com.example.service.EventService
import io.ktor.serialization.kotlinx.json.json
import io.ktor.server.application.Application
import io.ktor.server.application.install
import io.ktor.server.plugins.contentnegotiation.ContentNegotiation
import io.ktor.server.plugins.statuspages.StatusPages
import io.ktor.server.response.respond
import io.ktor.server.routing.get
import io.ktor.server.routing.routing

fun Application.module() {
    install(ContentNegotiation) {
        json()
    }

    install(StatusPages) {
        exception<IllegalArgumentException> { call, cause ->
            call.respond(mapOf("error" to cause.message.orEmpty()))
        }
    }

    val repository: EventRepository = when ((System.getenv("EVENTS_STORAGE") ?: "memory").lowercase()) {
        "postgres", "postgresql" -> {
            val dataSource = DatabaseFactory.createPostgresDataSource()
            DatabaseFactory.runMigrations(dataSource)
            val eventDao = JdbcEventDao(dataSource)
            PostgresEventRepository(eventDao)
        }
        else -> InMemoryEventRepository()
    }

    val service = EventService(repository)
    val controller = EventController(service)

    routing {
        get("/health") {
            call.respond(mapOf("status" to "ok"))
        }
        controller.register(this)
    }
}

package com.example.db

import com.zaxxer.hikari.HikariConfig
import com.zaxxer.hikari.HikariDataSource
import javax.sql.DataSource

object DatabaseFactory {
    fun createPostgresDataSource(): DataSource {
        val config = HikariConfig().apply {
            jdbcUrl = System.getenv("DATABASE_URL") ?: "jdbc:postgresql://localhost:5432/utcnevents"
            username = System.getenv("DATABASE_USER") ?: "postgres"
            password = System.getenv("DATABASE_PASSWORD") ?: "postgres"
            driverClassName = "org.postgresql.Driver"
            maximumPoolSize = 5
            isAutoCommit = true
            transactionIsolation = "TRANSACTION_READ_COMMITTED"
            validate()
        }
        return HikariDataSource(config)
    }

    fun initializeSchema(dataSource: DataSource) {
        val schemaSql = this::class.java.classLoader
            .getResource("db/schema.sql")
            ?.readText()
            ?: error("Missing db/schema.sql resource")

        dataSource.connection.use { connection ->
            connection.createStatement().use { statement ->
                statement.execute(schemaSql)
            }
        }
    }
}

package com.example.db

import com.zaxxer.hikari.HikariConfig
import com.zaxxer.hikari.HikariDataSource
import org.flywaydb.core.Flyway
import javax.sql.DataSource

object DatabaseFactory {
    fun createPostgresDataSource(): DataSource {
        val config = HikariConfig().apply {
            jdbcUrl = System.getenv("DATABASE_URL") ?: "jdbc:postgresql://localhost:5432/utcnevents"
            username = System.getenv("DATABASE_USER") ?: "postgres"
            password = System.getenv("DATABASE_PASSWORD") ?: "postgres"
            driverClassName = "org.postgresql.Driver"
            maximumPoolSize = 5
            isAutoCommit = true
            transactionIsolation = "TRANSACTION_READ_COMMITTED"
            validate()
        }
        return HikariDataSource(config)
    }

    fun runMigrations(dataSource: DataSource) {
        Flyway.configure()
            .dataSource(dataSource)
            .locations("classpath:db/migration")
            .baselineOnMigrate(true)
            .load()
            .migrate()
    }
}

package com.example.db.dao
import com.example.model.Event
interface EventDao { fun findAll(): List<Event> fun findById(id: Long): Event? fun create(event: Event): Event fun update(id: Long, event: Event): Event? fun delete(id: Long): Boolean }

package com.example.db.dao
import com.example.model.Event import javax.sql.DataSource
class JdbcEventDao(private val dataSource: DataSource) : EventDao { override fun findAll(): List<Event> = dataSource.connection.use { connection -> connection.prepareStatement( """ SELECT id, title, description, date, category, department FROM events ORDER BY id """.trimIndent() ).use { statement -> statement.executeQuery().use { rs -> buildList { while (rs.next()) { add(rs.toEvent()) } } } } }
override fun findById(id: Long): Event? = dataSource.connection.use { connection -> connection.prepareStatement( """ SELECT id, title, description, date, category, department FROM events WHERE id = ? """.trimIndent() ).use { statement -> statement.setLong(1, id) statement.executeQuery().use { rs -> if (rs.next()) rs.toEvent() else null } } }
override fun create(event: Event): Event = dataSource.connection.use { connection -> connection.prepareStatement( """ INSERT INTO events(title, description, date, category, department) VALUES (?, ?, ?, ?, ?) RETURNING id, title, description, date, category, department """.trimIndent() ).use { statement -> statement.setString(1, event.title) statement.setString(2, event.description) statement.setString(3, event.date) statement.setString(4, event.category) statement.setString(5, event.department) statement.executeQuery().use { rs -> rs.next() rs.toEvent() } } }
override fun update(id: Long, event: Event): Event? = dataSource.connection.use { connection -> connection.prepareStatement( """ UPDATE events SET title = ?, description = ?, date = ?, category = ?, department = ? WHERE id = ? RETURNING id, title, description, date, category, department """.trimIndent() ).use { statement -> statement.setString(1, event.title) statement.setString(2, event.description) statement.setString(3, event.date) statement.setString(4, event.category) statement.setString(5, event.department) statement.setLong(6, id) statement.executeQuery().use { rs -> if (rs.next()) rs.toEvent() else null } } }
override fun delete(id: Long): Boolean = dataSource.connection.use { connection -> connection.prepareStatement("DELETE FROM events WHERE id = ?").use { statement -> statement.setLong(1, id) statement.executeUpdate() > 0 } }
private fun java.sql.ResultSet.toEvent(): Event = Event( id = getLong("id"), title = getString("title"), description = getString("description"), date = getString("date"), category = getString("category"), department = getString("department") ) }

package com.example.repository
import com.example.model.Event import javax.sql.DataSource
class PostgresEventRepository(private val dataSource: DataSource) : EventRepository { override fun findAll(): List<Event> = dataSource.connection.use { connection -> connection.prepareStatement( """ SELECT id, title, description, date, category, department FROM events ORDER BY id """.trimIndent() ).use { statement -> statement.executeQuery().use { rs -> buildList { while (rs.next()) { add(rs.toEvent()) } } } } }
override fun findById(id: Long): Event? = dataSource.connection.use { connection -> connection.prepareStatement( """ SELECT id, title, description, date, category, department FROM events WHERE id = ? """.trimIndent() ).use { statement -> statement.setLong(1, id) statement.executeQuery().use { rs -> if (rs.next()) rs.toEvent() else null } } }
override fun create(event: Event): Event = dataSource.connection.use { connection -> connection.prepareStatement( """ INSERT INTO events(title, description, date, category, department) VALUES (?, ?, ?, ?, ?) RETURNING id, title, description, date, category, department """.trimIndent() ).use { statement -> statement.setString(1, event.title) statement.setString(2, event.description) statement.setString(3, event.date) statement.setString(4, event.category) statement.setString(5, event.department) statement.executeQuery().use { rs -> rs.next() rs.toEvent() } } }
override fun update(id: Long, event: Event): Event? = dataSource.connection.use { connection -> connection.prepareStatement( """ UPDATE events SET title = ?, description = ?, date = ?, category = ?, department = ? WHERE id = ? RETURNING id, title, description, date, category, department """.trimIndent() ).use { statement -> statement.setString(1, event.title) statement.setString(2, event.description) statement.setString(3, event.date) statement.setString(4, event.category) statement.setString(5, event.department) statement.setLong(6, id) statement.executeQuery().use { rs -> if (rs.next()) rs.toEvent() else null } } }
override fun delete(id: Long): Boolean = dataSource.connection.use { connection -> connection.prepareStatement("DELETE FROM events WHERE id = ?").use { statement -> statement.setLong(1, id) statement.executeUpdate() > 0 } }
private fun java.sql.ResultSet.toEvent(): Event = Event( id = getLong("id"), title = getString("title"), description = getString("description"), date = getString("date"), category = getString("category"), department = getString("department") ) }
